-- ============================================================
-- Quick fix: Seed the 5 empty tables + fix RLS for full app access
-- Run this in Supabase SQL Editor (Dashboard → SQL Editor → New Query)
-- ============================================================

-- Fix RLS: allow anon full access to ALL tables (app uses anon key)
DO $$
DECLARE
  tbl TEXT;
BEGIN
  FOR tbl IN
    SELECT unnest(ARRAY[
      'profiles', 'brands', 'talents', 'partnerships', 'activities',
      'approval_items', 'outreach_sequences', 'outreach_emails', 'outreach_metrics',
      'marketplace_opportunities', 'opportunity_applications', 'deal_notes',
      'tasks', 'notifications', 'teams', 'team_members',
      'user_subscriptions', 'billing_history',
      'partnership_proposals', 'activation_checklists', 'planning_timelines'
    ])
  LOOP
    EXECUTE format('DROP POLICY IF EXISTS "Allow all for authenticated" ON %I', tbl);
    EXECUTE format('DROP POLICY IF EXISTS "Allow read for anon" ON %I', tbl);
    EXECUTE format('DROP POLICY IF EXISTS "Allow all for anon" ON %I', tbl);
    EXECUTE format('CREATE POLICY "Allow all for authenticated" ON %I FOR ALL TO authenticated USING (true) WITH CHECK (true)', tbl);
    EXECUTE format('CREATE POLICY "Allow all for anon" ON %I FOR ALL TO anon USING (true) WITH CHECK (true)', tbl);
  END LOOP;
END $$;

-- Disable RLS on reference/lookup tables entirely
ALTER TABLE rate_benchmarks DISABLE ROW LEVEL SECURITY;
ALTER TABLE platform_multipliers DISABLE ROW LEVEL SECURITY;
ALTER TABLE category_premiums DISABLE ROW LEVEL SECURITY;
ALTER TABLE viewership_tiers DISABLE ROW LEVEL SECURITY;
ALTER TABLE subscription_plans DISABLE ROW LEVEL SECURITY;
ALTER TABLE culture_events DISABLE ROW LEVEL SECURITY;
ALTER TABLE mega_events DISABLE ROW LEVEL SECURITY;
ALTER TABLE conferences DISABLE ROW LEVEL SECURITY;
ALTER TABLE demographic_segments DISABLE ROW LEVEL SECURITY;
ALTER TABLE roi_benchmarks DISABLE ROW LEVEL SECURITY;
ALTER TABLE industry_guides DISABLE ROW LEVEL SECURITY;

-- CULTURE EVENTS (27 rows)
ON CONFLICT DO NOTHING;

-- MEGA EVENTS (10 rows)
ON CONFLICT DO NOTHING;

-- CONFERENCES (10 rows)
ON CONFLICT DO NOTHING;

-- DEMOGRAPHIC SEGMENTS (8 rows)
ON CONFLICT DO NOTHING;

-- INDUSTRY GUIDES (8 rows)
ON CONFLICT DO NOTHING;

