INSERT INTO demographic_segments (name, description, age_range, gender, interests, population_size, buying_power, media_preferences, top_events, key_cultural_moments, brand_activation_tips, activation_tips) VALUES
  ('Gen Z Trendsetters',     'Fashion and culture-forward Gen Z digital natives',  '18-26', 'all',         '["fashion","music","gaming","social justice","sustainability"]', '68M (US)', '$360B annual spending', 'TikTok, Instagram Reels, YouTube Shorts, Snapchat — short-form video dominant, meme culture, authentic UGC', 'Coachella, ComplexCon, Pride Month, Halloween, Black Friday', 'Pride Month, Earth Day, Mental Health Awareness, Black History Month', 'Lead with authenticity over polish. Co-create with creators rather than scripting. Use TikTok challenges and AR filters. Values-driven messaging converts.', 'Use TikTok and Instagram Reels. Co-create campaigns. Prioritise values-driven messaging.'),
  ('Millennial Parents',     'Millennial parents balancing family and career',      '30-40', 'all',         '["parenting","home","health","finance","education"]', '45M (US)', '$2.5T household spending', 'Instagram, Facebook, YouTube, Pinterest — researching purchases, family content, educational videos', 'Back to School, Thanksgiving, Christmas, Memorial Day, Fourth of July', 'Back to School, Thanksgiving, Christmas, Mental Health Awareness', 'Relatable parenting content converts. Product integrations in daily routines. Educational content for kids. Family-friendly unboxing and reviews.', 'Create relatable family content. Integrate products into daily routines. Family-friendly reviews.'),
  ('Fitness Enthusiasts',    'Dedicated health and fitness consumers',              '22-38', 'all',         '["fitness","nutrition","wellness","sports","outdoor"]', '32M (US)', '$1.2T wellness economy', 'Instagram, TikTok, YouTube — workout videos, transformation stories, supplement and gear reviews', 'Super Bowl, March Madness, Olympics, World Cup, Back to School', 'New Year (resolutions), Summer prep, Mental Health Awareness', 'Challenge-based campaigns drive participation. Partner with certified trainers. Transformation content converts. Ambassador programs over one-off posts.', 'Run 30-day challenges. Partner with certified trainers. Use before/after transformation content.'),
  ('Tech Early Adopters',    'Technology enthusiasts who adopt before mainstream',   '25-45', 'male_skew',   '["technology","gaming","productivity","AI","gadgets"]', '18M (US)', '$800B annual tech spending', 'YouTube (long-form reviews), Twitter/X, LinkedIn, Reddit — deep-dive reviews, comparison content, tech forums', 'CES, SXSW, VidCon, Apple Events, Black Friday/Cyber Monday', 'CES week, product launch cycles, Back to School tech', 'Detailed unboxing and review content. Comparison and versus formats. Early access exclusives build excitement. Data-driven talking points for authenticity.', 'Invest in detailed YouTube reviews. Provide early exclusive access. Use comparison formats.'),
  ('Beauty Conscious',       'Beauty and personal care focused consumers',           '16-35', 'female_skew', '["beauty","skincare","fashion","wellness","self-care"]', '55M (US)', '$580B global beauty market', 'Instagram, TikTok, YouTube — GRWM content, tutorials, product reviews, routine-based formats', 'Met Gala, NYFW, Coachella, Valentines Day, Pride Month', 'Pride Month, Valentines Day, International Womens Day, Diwali', 'GRWM and routine-based content outperforms scripted ads. Partner with creators who organically use similar products. TikTok for discovery, Instagram for conversion.', 'Prioritise GRWM content. Let creators choose products. TikTok for discovery, IG for conversion.'),
  ('Gen Alpha Influence',    'Parents purchasing on behalf of Gen Alpha (2010-2025)', '0-15',  'all',        '["toys","gaming","education","entertainment","kids content"]', '48M (US)', '$500B+ influenced spending', 'YouTube, TikTok, Roblox — kids content, gaming, educational videos, family channels', 'Back to School, Christmas, Halloween, Summer Break', 'Christmas, Back to School, Halloween, Summer Break', 'Family-friendly unboxing and educational content. Partner through parent-approved channels. YouTube Kids and TikTok safety-first approach. Toy and game reviews drive purchase intent.', 'Use family-friendly unboxing. Partner with parent-approved channels. YouTube Kids safety-first.'),
  ('Affluent Professionals', 'High-income professionals with discretionary spending', '35-55', 'all',        '["finance","luxury","travel","business","wellness"]', '22M (US)', '$3.4T combined income', 'LinkedIn, YouTube, Instagram, Twitter/X — thought leadership, premium reviews, travel content, business insights', 'Art Basel, NYFW, Cannes Lions, CES, Advertising Week', 'Tax season, year-end giving, summer travel, holiday luxury gifting', 'Thought-leadership content over influencer marketing. LinkedIn posts perform well. Premium product reviews with expertise. Quality over trends in messaging.', 'Use thought leadership on LinkedIn. Expertise-driven premium reviews. Quality over trend messaging.'),
  ('Multicultural Gen Z',    'Hispanic, Black, AAPI Gen Z consumers shaping culture', '18-28', 'all',       '["music","fashion","food","culture","social justice","gaming"]', '42M (US)', '$600B+ combined spending', 'TikTok, Instagram, YouTube, Snapchat — culturally authentic content, bilingual creators, social commerce', 'Pride Month, Juneteenth, Hispanic Heritage Month, Lunar New Year, Diwali', 'Black History Month, AAPI Heritage, Hispanic Heritage, Lunar New Year, Juneteenth, Ramadan', 'Culturally authentic storytelling is non-negotiable. Bilingual content expands reach. Community-first campaigns build loyalty. Social commerce converts.', 'Lead with cultural authenticity. Use bilingual content. Community-first campaigns build loyalty.')
INSERT INTO industry_guides (title, industry, content, sector, budget_allocation, priority_tier_1_events, tier_2_events, heritage_awareness_months, key_conferences, best_demographics, activation_strategies) VALUES
  ('Beauty & Skincare Creator Partnerships', 'Beauty & Personal Care', 'The beauty industry leads in influencer marketing spend with the highest ROI from micro and mid-tier creators using GRWM and routine-based content.', 'Skincare, Cosmetics, Personal Care', '$50K–$250K per campaign', 'Met Gala, NYFW, Coachella, Pride Month', 'Valentines Day, International Womens Day, Diwali, Black Friday', 'Womens History Month, Pride Month, AAPI Heritage Month, Hispanic Heritage Month', 'Influencer Marketing Show, SMMW, Cannes Lions', 'Beauty Conscious, Gen Z Trendsetters, Multicultural Gen Z', 'Prioritise GRWM and routine-format content. Partner with creators who organically use similar products. Allow 4-6 weeks for seeding. Offer affiliate codes alongside flat fees. TikTok for discovery, Instagram for conversion.'),
  ('Tech Product Launch Playbook', 'Technology', 'Tech brands see highest ROI with YouTube integrations and detailed review content. Trust is paramount — creators must genuinely evaluate products.', 'Consumer Electronics, Software, SaaS', '$75K–$500K per launch', 'CES, SXSW, Apple Events, Black Friday/Cyber Monday', 'Back to School, VidCon, Product Launch Windows', 'None — focus on product launch cycles and seasonal demand', 'CES, SXSW, VidSummit, Creator Economy Expo', 'Tech Early Adopters, Affluent Professionals, Gen Z Trendsetters', 'Invest in long-form YouTube reviews over short social posts. Provide early exclusive access. Use comparison and versus content. Run campaigns around CES and launch cycles. Data-driven talking points for authenticity.'),
  ('Fitness & Wellness Brand Guide', 'Sports & Fitness', 'Fitness creators command high trust and engagement. Challenge-based campaigns drive participation and UGC at massive scale.', 'Equipment, Apparel, Supplements, Wellness', '$40K–$200K per campaign', 'Super Bowl, Olympics, World Cup, March Madness', 'New Year Resolutions, Summer Prep, Back to School, Mental Health Awareness Month', 'Mental Health Awareness Month (May)', 'VidSummit, SMMW, Brand Innovation Summit', 'Fitness Enthusiasts, Gen Z Trendsetters, Millennial Parents', 'Run 30-day challenge campaigns for maximum UGC. Partner with certified trainers for supplement credibility. Use Instagram Reels and TikTok for workout content. Invest in ambassador programs over one-off posts. Time around New Year and summer.'),
  ('Food & Beverage Creator Strategy', 'Food & Beverage', 'Food content performs exceptionally on TikTok and Instagram. Authentic recipe integrations outperform scripted ads by 3x.', 'CPG, Restaurants, Meal Delivery, Beverages', '$25K–$150K per campaign', 'Super Bowl (ads), Thanksgiving, Black Friday, World Cup watch parties', 'Memorial Day (BBQ), Fourth of July, Back to School lunches, Halloween', 'Hispanic Heritage Month, Lunar New Year, Ramadan (Iftar), Diwali', 'SMMW, Brand Innovation Summit, Influencer Marketing Show', 'Millennial Parents, Fitness Enthusiasts, Multicultural Gen Z', 'Use recipe integration format over product-only showcases. Partner with micro food bloggers for highest engagement. Leverage TikTok recipe trends. Run seasonal campaigns tied to holidays and cultural food moments. Genuine reactions only.'),
  ('Fashion & Apparel Partnership Guide', 'Fashion & Apparel', 'Fashion thrives on visual platforms. Haul, try-on and styling content converts at the highest rates. Diversity directly correlates with reach.', 'Streetwear, Luxury, Athleisure, DTC', '$50K–$300K per campaign', 'NYFW, Met Gala, Coachella, ComplexCon, Black Friday', 'Pride Month, Back to School, Halloween, Valentines Day', 'Black History Month, Pride Month, Hispanic Heritage Month, AAPI Heritage Month', 'ComplexCon, NYFW events, Cannes Lions, Advertising Week', 'Gen Z Trendsetters, Beauty Conscious, Multicultural Gen Z', 'Invest in try-on haul and styling content over static shots. Cast diverse creators for maximum reach. Time campaigns around fashion weeks and seasonal drops. Offer exclusive early-access through creators. Enable social commerce with shoppable links.'),
  ('Gaming & Esports Activation Guide', 'Gaming', 'Gaming creators offer unmatched live engagement on Twitch and YouTube. Non-endemic brands increasingly activate as the audience matures.', 'Game Publishers, Hardware, Esports, Non-endemic', '$40K–$250K per campaign', 'TwitchCon, E3/Summer Game Fest, The Game Awards, ComplexCon', 'Major game launches, Esports tournaments, Back to School, Black Friday', 'None — focus on game release calendars and esports schedules', 'TwitchCon, CES (gaming), VidSummit, Creator Economy Expo', 'Tech Early Adopters, Gen Z Trendsetters, Gen Alpha Influence', 'Use Twitch integrations and live stream sponsorships for real-time engagement. YouTube gaming for evergreen content. Non-endemic brands lead with creator authenticity. Run campaigns around major game launches. Enable creator codes and in-game items.'),
  ('Finance & Fintech Creator Compliance Guide', 'Finance & Fintech', 'Finance content requires careful compliance navigation but delivers high CLV. Educational content on YouTube and LinkedIn performs best.', 'Banking, Insurance, Fintech, Crypto, Investing', '$50K–$300K per campaign', 'Tax Season (Jan-Apr), Year-End Financial Planning, Black Friday (financial products)', 'Back to School (student finance), New Year (budgeting resolutions)', 'None — focus on financial planning seasonal cycles', 'Cannes Lions, Advertising Week, Brand Innovation Summit', 'Affluent Professionals, Tech Early Adopters, Millennial Parents', 'Work with creators who have demonstrated financial literacy. Ensure all content passes compliance review. Favour educational explainer content. Use LinkedIn alongside YouTube for B2B fintech. Provide clear disclosure templates and approved talking points.'),
  ('Travel & Hospitality Creator Playbook', 'Travel & Hospitality', 'Travel content has strong long-tail value — destination videos drive bookings months after publication. Instagram and YouTube are primary platforms.', 'Hotels, Airlines, Tourism Boards, OTAs', '$30K–$200K per campaign', 'Summer Travel Season (Jun-Aug), Spring Break, Holiday Travel, Art Basel Miami', 'Memorial Day, Fourth of July, Thanksgiving travel, Valentines Day getaways', 'None — focus on booking windows and travel seasons', 'SXSW (travel tech), Cannes Lions, Advertising Week', 'Affluent Professionals, Millennial Parents, Gen Z Trendsetters', 'Invest in YouTube destination guides for long-tail search value. Instagram Reels for aspirational visual content. Partner for hosted trips with clear deliverables. Time around booking windows: January, spring break and summer. Enable booking links with tracked attribution.')
